package com.miaojizhang.app;
import android.app.Activity;import android.os.Bundle;import android.view.*;import android.webkit.*;import android.widget.*;import android.graphics.Color;
public class MainActivity extends Activity{FrameLayout root;TextView splash;public void onCreate(Bundle b){super.onCreate(b);root=new FrameLayout(this);WebView w=new WebView(this);WebSettings s=w.getSettings();s.setJavaScriptEnabled(true);s.setDomStorageEnabled(true);s.setDatabaseEnabled(true);s.setAllowFileAccess(true);s.setAllowContentAccess(true);w.setBackgroundColor(Color.rgb(255,248,239));w.setWebViewClient(new WebViewClient(){public void onPageFinished(WebView v,String u){if(splash!=null){root.removeView(splash);splash=null;}}});root.addView(w,new FrameLayout.LayoutParams(-1,-1));splash=new TextView(this);splash.setText("秒记账");splash.setTextSize(34);splash.setTextColor(Color.rgb(41,41,41));splash.setGravity(Gravity.CENTER);splash.setBackgroundColor(Color.rgb(255,248,239));splash.setTypeface(android.graphics.Typeface.DEFAULT_BOLD);root.addView(splash,new FrameLayout.LayoutParams(-1,-1));setContentView(root);w.loadUrl("file:///android_asset/index.html");}}
